document.addEventListener('click',function(e){
    let btn=e.target.closest('[data-view-client]');
    if(btn){
        let clientId=btn.dataset.viewClient;

        fetch(`${API_URL}/requests?clientId=${clientId}`)
        .then(r=>r.json())
        .then(reqs=>{
            let screen=document.querySelector('[data-screen="matches"] .content');
            screen.innerHTML='';

            reqs.forEach(r=>{
                let card=document.createElement('div');
                card.className='card';
                card.innerHTML=`
                    <strong>${r.brand} ${r.model}</strong>
                    <span class="badge">${r.status}</span>
                `;
                screen.appendChild(card);
            });

            showScreen('matches');
        });
    }
});
